import React, { useState } from 'react';

const UserAuth = () => {
    const [isLogin,setIsLogin]=useState(false);
    const [haveAccount, setHaveAccount] = useState(false);
    function toggleLogin() {
        setHaveAccount(!haveAccount);
    }
    return (
        <>
            <div className='login-container'>
                <div className='login'>
                    <div className='sub-heading-login'>
                        <p>Please enter your details</p>
                    </div>
                    <div className='heading-login'>Welcome back</div>
                    <div className='name-input'>
                        <input type='text' placeholder='Name' className='input-box' />
                    </div>
                    <div className='email-input'>
                        <input type='email' placeholder='Email address' className='input-box' />
                    </div>
                    <div className='password-input'>
                        <input type='password' placeholder='Password' className='input-box' />
                    </div>

                    {!haveAccount ? <div className='password-input'>
                        <input type='password' placeholder='confirm Password' className='input-box' />
                    </div> : ''
                    }
                    <div >
                        <button className='signup-button'>{!haveAccount ? 'SIGNIN':'LOGIN'}</button>
                    </div>
                    <div>
                        <p onClick={toggleLogin} className="have-account">Already have account Login</p>
                    </div>
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
                p{
                   color:var(--font-text);
                }
                input{
                    background-color:var(--secondary-color);
                    color:var(--font-text);
                    border:none;
                    font-weight:bold;
                }
               .login{
                   color:var(--font-text);
                   border:2px solid var(--font-text);
                   width:400px;
                   border-radius:10px;
                   display:flex;
                   flex-direction:column;
               }
                .sub-heading-login{
                   color:grey;
                   font-size:15px;
                   display:flex;
                   justify-content:left;
                   padding-left:50px;
                }
                .heading-login{
                   font-weight:bold;
                   font-size:28px;
                   display:flex;
                   justify-content:left;
                   padding-left:50px;
                   margin-bottom:12px;
                }
                .login-container{  
                   height:100vh;             
                   display:flex;
                   align-items:center;
                   justify-content:center;
               }
               .input-box{
                    padding:10px;
                    border-radius:5px;
                    width:70%;
                }
                .email-input,.password-input,.name-input{
                   margin-bottom:20px;
                }
                .remember-box{
                    display:flex;
                    flex-direction:row;
                    gap:5%;
                    align-items:center;
                    margin-bottom:15px;
                    justify-content:center;
                    font-size:15px;
                }
                .signup-button{
                    background-color:var(--button-color);
                    color:var(--bg-parchment);
                    width:75%;
                    border:none;
                    margin:10px;
                    border-radius:10px;
                    padding:10px;
                    font-size:1.5rem;
                    font-family: 'January', sans-serif;
                }
                .have-account{
                   cursor:pointer;
                }
            `}</style>
}

export default UserAuth
